/** * TAB090001 - 월별 집계 (수량) */
<template>
 <div>
    <div class="search_box">
      <b-row class="search_area">
        <b-col cols="1" class="period">
          <div class="form-floating me-1">
            <date-picker label="연도" mode="year" v-model="params.year" />
            <label for="floatingSelect" class="select">년도</label>
          </div>
        </b-col>
          <b-col cols="1" class="period">
            <div class="form-floating me-1">
              <b-form-select v-model="params.month" :options="monthOptions" class="form-control" style="padding-left: 60px; min-width: 150px;" />
              <label for="floatingSelect" class="select">기준월</label>
            </div>
          </b-col>
        <b-col cols="2" class="ms-3">
          <div class="form-floating">
            <input autocomplete="off" type="text" class="form-control label-60" id="floating" placeholder="Site" v-model="params.site" :disabled="true" />
            <label for="floating">사업장</label>
          </div>
        </b-col>
      </b-row>
      <div class="btn_area">
        <b-button @click="searchClick"><span class="ico_search"></span>조회</b-button>
      </div>
    </div>
    <div class="grid_box search_onerow">
      <div class="left_box">
        <div class="btn_wrap ms-auto">
          <b-button class="second" @click="excelBtnClick">엑셀</b-button>
        </div>
      </div>
      <div class="grid-border-none">
        <RealGrid ref="prodSubulGrid" :uid="'prodSubulGrid'" :grid="prodSubulGrid" :layout="prodSubulGrid.columnLayout" :step="'1'" :rows="prodSubulGridRows" style="height: 100%" :fitLayoutWidthEnable="false" />
      </div>
    </div>
  </div>
</template>

<script>
import { useUserAuthInfo } from '@store/auth/userAuthInfo';
import { useC0001001 } from '@web/store/C0001001.js';
import gridField from '@web/c0009000/js/TAB090001.js';

export default {
  props: {},
  components: {},
  setup() {
    const srchInfo = useC0001001();
    const userAuthInfo = useUserAuthInfo();
    return { 
      srchInfo,
      userAuthInfo 
    };
  },
  data() {
    return {
      prodSubulGrid: null,
      prodSubulDtlGrid: null,      
      prodSubulGridRows: [],

      yearSelected: false,
      syncingYearToMonth: false,
      isInitializing: true,

      yearRowsCache: [],
      yearCacheKey: null,
      
      monthOptions: [
        { value: null, text: '전체' },
        { value: '01', text: '1월' },
        { value: '02', text: '2월' },
        { value: '03', text: '3월' },
        { value: '04', text: '4월' },
        { value: '05', text: '5월' },
        { value: '06', text: '6월' },
        { value: '07', text: '7월' },
        { value: '08', text: '8월' },
        { value: '09', text: '9월' },
        { value: '10', text: '10월' },
        { value: '11', text: '11월' },
        { value: '12', text: '12월' },
      ],

      params: {
        year: null,
        month: null,
        yyyymm: null,
        viewMode: 'YEAR',
        site: 'HQ',
      },
      siteMap: {
        본사: 'HQ',
        VINA: 'VN',
        HQ: 'HQ',
        VN: 'VN',
      },
    };
  },
   watch: {
    'params.year': function(newVal) {
        if (!newVal) {
          this.yearSelected = false;
          this.params.month = null;
          this.params.yyyymm = null;
          this.params.viewMode = 'YEAR';

          return;
        }

        if (!this.isInitializing) {
          this.yearSelected = true;
        }

        const yyyy = String(newVal);

        if (this.params.month) {
          const mm = String(this.params.month);
          this.params.yyyymm = `${yyyy}${mm}`;
          this.params.viewMode = 'MONTH';
        } else {
          this.params.yyyymm = null;
          this.params.viewMode = 'YEAR';
        }
        
        this.clearYearCache();
    },
    'params.month': function(newVal) {
        if (!newVal) {
          this.params.yyyymm = null;
          this.params.viewMode = 'YEAR';
          return;
        }

        if (!this.isInitializing) {
          const yyyy = String(this.params.year);
          const mm = String(newVal);
          this.params.yyyymm = `${yyyy}${mm}`;
          this.params.viewMode = 'MONTH';
        }
    },
    prodCtg: {
      handler(newVal) {
        if (newVal) {
          this.params.site = newVal === 'VN' ? 'VINA' : '본사';
          if (this.$refs.prodSubulGrid != null) {
            this.initialize();
            this.searchClick();
          }
        }
      },
    },
  },
  computed: {
    showMonth() {
      return this.yearSelected;
    },
    activeGrid() {
      return this.params.viewMode === 'MONTH' ? this.manuCostDtlGrid : this.manuCostGrid;
    },
    gridKey() {
      return this.params.viewMode === 'MONTH' ? 'MONTH' : 'YEAR';
    },
    gridView() {
      return this.$refs.prodSubulGrid.getGridView();
    },
    gridDataProvider() {
      return this.$refs.prodSubulGrid.getGridDataProvider();
    },
    prodCtg() {
      return this.userAuthInfo.curProdCtg;
    },
  },
  created() {
    this.isInitializing = true;
    this.initialize();
    this.initializeGrid();
    this.$nextTick(() => {
      this.isInitializing = false;
    });
  },
  mounted() {
     const gv = this.gridView;

    if (this.prodSubulGrid.columnLayout) {
      gv.setColumnLayout(this.prodSubulGrid.columnLayout);
    }

    gv.setRowStyleCallback((grid, item, fixed) => {
      const row = item.dataRow;
      if (row == null || row < 0) return null;

      const rowType = (grid.getValue(row, 'rowType') || '').toString();
      console.log('rowStyleCallback:', row, rowType);

      if (rowType === 'SUBTOTAL') {
        return {
          style: {
            background: '#f5f7ff',
            fontWeight: 'bold',
          },
        };
      }

      if (rowType === 'TOTAL') {
        return {
          style: {
            background: '#fff3cd',
            fontWeight: 'bold',
          },
        };
      }

      return null;
    });

    const layoutGubun = gv.layoutByColumn('구분');
    if (layoutGubun) {
      layoutGubun.spanCallback = (grid, layout, itemIndex) => {
        const dataRow = grid.getDataRow(itemIndex);
        if (dataRow == null || dataRow < 0) return 1;

        const rowType = String(grid.getValue(itemIndex, 'rowType') || '');
        const totalKind = String(grid.getValue(itemIndex, 'totalKind') || '');

        if (rowType === 'SUBTOTAL') return 5;

        if (rowType === 'TOTAL') {
          if (totalKind === 'MONTH_TOTAL') return 5;
          if (totalKind === 'SITE_TOTAL')  return 2;
          return 2;
        }
        return 1;
      };
    }

    const layoutInch = gv.layoutByColumn('inch');
    if (layoutInch) {
      layoutInch.spanCallback = (grid, layout, itemIndex) => {
        const dataRow = grid.getDataRow(itemIndex);
        if (dataRow == null || dataRow < 0) return 1;

        const rowType = String(grid.getValue(dataRow, 'rowType') || '');
        const totalKind = String(grid.getValue(dataRow, 'totalKind') || '');

        if (rowType === 'TOTAL') {
          if (totalKind === 'MONTH_TOTAL') return 3;
          if (totalKind === 'SITE_TOTAL')  return 3;
        }
        return 1;
      };
    }
  },
  beforeUnmount() {},
  methods: {
    initialize() {
      const baseYyyymm = this.srchInfo.yyyymm;
      const defaultYear = baseYyyymm 
        ? String(baseYyyymm).substring(0, 4) 
        : String(new Date().getFullYear());

      this.params.year = defaultYear;
      this.params.month = null;
      this.params.yyyymm = null;
      this.params.viewMode = 'YEAR';

      this.yearSelected = false;
      this.params.site = this.userAuthInfo.curProdCtg === 'VN' ? 'VINA' : '본사';
    },
    clearYearCache() {
      this.yearRowsCache = [];
      this.yearCacheKey = null;
    },
    parseMonthNumber(monthText) {
      const m = String(monthText || '').match(/(\d{1,2})\s*월/);
      if (!m) return null;
      const mm = Number(m[1]);
      return mm >= 1 && mm <= 12 ? mm : null;
    },
    async fetchYearRowsIfNeeded() {
      const yyyy = this.params.year;
      const site = this.params.site != null ? this.siteMap[this.params.site] : null;
      const key = `${yyyy}|${site || ''}`;

      if (this.yearCacheKey === key && Array.isArray(this.yearRowsCache) && this.yearRowsCache.length) {
        return this.yearRowsCache;
      }

      const param = {
        menuId: 'c0009000',
        queryId: 'C0009001_Tab090001',
        queryParams: { yyyy, site },
        target: [],
      };

      const resp = await this.$axios.api.search(param);

      let rows = [];
      if (resp && resp.data) {
        rows = Array.isArray(resp.data) ? resp.data : (resp.data.rows || []);
      } else if (Array.isArray(resp)) {
        rows = resp;
      }

      rows = rows.map(r => {
        if (r == null) return r;
        if ('YYYYMM' in r || 'yyyymm' in r) return r;

        const mm = this.parseMonthNumber(r['월']);
        if (!mm) return r;

        const yyyymm = `${this.params.year}${String(mm).padStart(2, '0')}`;
        return { ...r, YYYYMM: yyyymm };
      });

      this.yearRowsCache = rows;
      this.yearCacheKey = key;
      return rows;
    },
    initializeGrid() {
      this.prodSubulGrid = _.cloneDeep(gridField);
    },
    onDateChange() {
      this.srchInfo.setSearchInfo({ yyyymm: this.params.yyyymm });
    },
    async getDataList() {
      this.gridView.commit();

      const yearRows = await this.fetchYearRowsIfNeeded();

      if (this.params.viewMode === 'YEAR') {
        // 연도 전체 조회 - 당해 총 생산실적
        this.prodSubulGridRows = this.buildProdSubulRows(yearRows, false);
        return;
      }

      // 특정 월 조회 - 당월 총 생산실적
      const selectedYYYYMM = String(this.params.yyyymm || '');
      const filtered = yearRows.filter(r => {
        const rowYYYYMM = String(r['YYYYMM'] || r['yyyymm'] || '');
        return rowYYYYMM === selectedYYYYMM;
      });

      this.prodSubulGridRows = this.buildProdSubulRows(filtered, true);
    },
    buildProdSubulRows(rows, isMonthView = false) {
      if (!Array.isArray(rows) || rows.length === 0) return [];

      const num = (v) => {
        const n = Number(v);
        return Number.isFinite(n) ? n : 0;
      };

      const numberCols = ['계획', '실적', 'boh', 'in', 'out', 'loss', 'eoh', 'outEtc'];
      const baseRows = rows.filter(r => {
        const monthVal = r['월'] || '';
        return monthVal !== '당월 총 생산실적' && monthVal !== '당해 총 생산실적';
      });

      const createSumRow = () =>
        numberCols.reduce((acc, c) => ((acc[c] = 0), acc), {});

      const accumulate = (target, source) => {
        numberCols.forEach((c) => {
          target[c] += num(source[c]);
        });
      };

      const totalSum = createSumRow();
      baseRows.forEach(r => accumulate(totalSum, r));

      // 월 선택 여부에 따라 표기 변경
      const totalLabel = isMonthView ? '당월 총 생산실적' : '당해 총 생산실적';

      const totalRow = {
        rowType: 'TOTAL',
        totalKind: 'MONTH_TOTAL',
        구분: totalLabel,
        모델: '',
        inch: '',
        판매처: '',
        월: totalLabel,
        ...totalSum,
        mergeKey: 'TOTAL|MONTH',
        mergeKeyGubun: 'TOTAL|MONTH',
      };

      const result = [];

      const groupMap = {};
      baseRows.forEach((r) => {
        const g = r['구분'] || '기타';
        if (!groupMap[g]) groupMap[g] = [];
        groupMap[g].push(r);
      });

      const orderedGubuns = [];
      if (groupMap['양산']) orderedGubuns.push('양산');
      if (groupMap['개발']) orderedGubuns.push('개발');
      if (groupMap['카세트']) orderedGubuns.push('카세트');
      Object.keys(groupMap).forEach((g) => {
        if (!orderedGubuns.includes(g)) orderedGubuns.push(g);
      });

      // 월 병합 처리: 연도 조회시에는 월별로 구분, 월 조회시에는 동일 mergeKey
      const getMonthKey = (r) => {
        if (isMonthView) return '';
        return r['월'] || r['YYYYMM'] || r['yyyymm'] || '';
      };

      const createSubtotal = (groupName) => ({
        rowType: 'SUBTOTAL',
        구분: `소계(${groupName})`,
        월: '',
        totalKind: '',

        ...createSumRow(),
        mergeKey: `SUBTOTAL|${groupName}`,
        mergeKeyGubun: `SUBTOTAL|${groupName}`,
      });

      let mergeGroupSeq = 0;

      orderedGubuns.forEach((g) => {
        const list = groupMap[g];
        if (!list || list.length === 0) return;

        const subtotal = createSubtotal(g);
        let lastKey = null;

        list.forEach((r) => {
          const prodKey = [
            r['구분'] || '',
            r['모델'] || r['model'] || '',
            r['inch'] || r['Inch'] || '',
            r['판매처'] || r['DW_SITE'] || r['dwSite'] || r['DW_Site'] || '',
            getMonthKey(r),
          ].join('|');

          if (prodKey !== lastKey) {
            mergeGroupSeq++;
            lastKey = prodKey;
          }

          const mergeKey = `DATA|${mergeGroupSeq}`;

          result.push({
            ...r,
            rowType: 'DATA',
            totalKind: '',
            mergeKey,
            mergeKeyGubun: mergeKey,
          });

          accumulate(subtotal, r);
        });

        result.push(subtotal);
      });

      const first = baseRows[0] || {};
      const dwSiteField =
        '판매처' in first ? '판매처' :
        'DW_SITE' in first ? 'DW_SITE' :
        'dwSite' in first ? 'dwSite' :
        'DW_Site' in first ? 'DW_Site' :
        null;

      if (dwSiteField) {
        const siteTotals = {};
        baseRows.forEach((r) => {
          const key = r[dwSiteField];
          if (!key) return;

          if (!siteTotals[key]) siteTotals[key] = createSumRow();
          accumulate(siteTotals[key], r);
        });

        Object.keys(siteTotals).forEach((key) => {
          result.push({
            rowType: 'TOTAL',
            totalKind: 'SITE_TOTAL',
            구분: '판매처별',
            모델: '',
            inch: key,
            판매처: '',
            월: '',
            ...siteTotals[key],
            mergeKey: `TOTAL|SITE|${key}`,
            mergeKeyGubun: `TOTAL|SITE`,
          });
        });
      }

      return [totalRow, ...result];
    },

    accumulateRow(target, source, numberCols) {
      numberCols.forEach(col => {
        const v = Number(source[col]) || 0;
        target[col] += v;
      });
    },

    makeSubtotalRowByGroup(row, groupName) {
      return {
        ...row,
        rowType: 'SUBTOTAL',
        구분: `소계(${groupName})`,
        월: '',
        mergeKeyGubun: `SUBTOTAL|${groupName}`,
      };
    },

    makeTotalRow(row, dwSiteField, siteKey) {
      return {
        ...row,
        rowType: 'TOTAL',
        totalType: 'GRAND',
        구분: '당월 총 생산실적',
        모델: '',
        inch: siteKey,
        판매처: '',
        월: '당월 총 생산실적',
      };
    },
    searchClick() {
      this.getDataList();
    },
    async excelBtnClick() {
      const grid = this.gridView;

      const now = new Date();
      const yyyymmdd = this.$utils.getTodayDate();

      const hours = String(now.getHours()).padStart(2, '0');
      const minutes = String(now.getMinutes()).padStart(2, '0');
      const seconds = String(now.getSeconds()).padStart(2, '0');
      const fileName = `생산실적_월별집계_${yyyymmdd}_${hours}${minutes}${seconds}.xlsx`;

      const options = {
        type: 'excel',
        target: 'local',
        fileName: fileName,
        progressMessage: '엑셀 Export중입니다.',
        done: function () {
          alert('엑셀 내보내기가 완료되었습니다!');
        },
      };

      grid.exportGrid(options);
    },
  },
};
</script>
